var prev_queue_id = flow.get("prev_queue_id") || null;
var current_queue_id = msg.payload.mission_queue_id;

var outputMisionActual = null;
var outputMisionTerminada = null;

// Si el valor actual es null
if(current_queue_id === null) {
    outputMisionActual = {"payload": {"mision_actual": "Robot sin misión"}};

    if (prev_queue_id !== null) {
        outputMisionTerminada = {"payload": {"mision_terminada": prev_queue_id}};
    }
} else {
    // Si hay una misión actual
    outputMisionActual = {"payload": {"mision_actual": current_queue_id}};

    // Si hubo un cambio desde la última vez
    if(prev_queue_id !== null && prev_queue_id !== current_queue_id) {
        outputMisionTerminada = {"payload": {"mision_terminada": prev_queue_id}};
    }
}

// Guarda el valor actual para la próxima vez
flow.set("prev_queue_id", current_queue_id);

return [outputMisionActual, outputMisionTerminada];

// Variables de estado
var estadoActual = msg.payload.mision_actual === "Robot sin misión" ? "Inactivo" : "Activo";
var estadoAnterior = flow.get("estadoRobot") || null;
var timestamp = new Date().getTime();
var ultimoTimestamp = flow.get("ultimoTimestamp") || timestamp;

// Calcular duración desde el último ciclo (no acumulativa)
var duracionCiclo = timestamp - ultimoTimestamp;

// Si hay cambio de estado o es primera ejecución
if (estadoActual !== estadoAnterior) {
    // Registrar evento de cambio de estado si no es primera ejecución
    if (estadoAnterior !== null) {
        var msgCambio = {
            topic: "cambio_estado",
            payload: {
                estado: estadoAnterior,
                estado_nuevo: estadoActual,
                duracion: duracionCiclo,
                tiempo_inicio: ultimoTimestamp,
                tiempo_fin: timestamp,
                tipo: "cambio"
            }
        };

        // Actualizar estado
        flow.set("estadoRobot", estadoActual);

        // Guardar este timestamp para el próximo ciclo
        flow.set("ultimoTimestamp", timestamp);

        return msgCambio;
    }

    // Primera ejecución
    flow.set("estadoRobot", estadoActual);
}

// Para todas las actualizaciones normales
msg.payload = {
    estado: estadoActual,
    duracion: duracionCiclo,  // Duración desde el último ciclo
    tiempo_inicio: ultimoTimestamp,
    tiempo_fin: timestamp,
    tipo: "actualizacion"
};

// Actualizar timestamp para el próximo ciclo
flow.set("ultimoTimestamp", timestamp);

return msg;

var estadoActual = msg.payload.estado;
var duracion = msg.payload.duracion;

// Crear un nuevo objeto payload solo con los campos necesarios
msg.payload = {
    estado: estadoActual,
    duracion: duracion
};

return msg;
